   918→    private Map<String, Uuid> topicIdsForBatches(List<ProducerBatch> batches) {
   919→        return batches.stream()
   920→                .collect(Collectors.toMap(
   921→                        b -> b.topicPartition.topic(),
   922→                        b -> metadata.topicIds().getOrDefault(b.topicPartition.topic(), Uuid.ZERO_UUID),
   923→                        (existing, replacement) -> replacement)
   924→                );
   925→    }
