}

public void close() {
    recordsBuilder.close();
    if (!recordsBuilder.isControlBatch()) {
        CompressionRatioEstimator.updateEstimation(topicPartition.topic(),
                                                   recordsBuilder.compression().type(),
                                                   (float) recordsBuilder.compressionRatio());
    }
    reopened = false;
}

